// ── Config stubs ───────────────────────────────────────────────────

function configStub(role: Role): string {
  const name = role.charAt(0).toUpperCase() + role.slice(1);
  switch (role) {
    case "ceo":
      return `# CEO config\n\n## Notes\n\n[Add project-specific CEO notes here]\n`;
    case "cto":
      return [
        `# CTO config`,
        ``,
        `## Scan targets`,
        ``,
        `- [List key source files and directories]`,
        `- \`package.json\``,
        ``,
        `## Build command`,
        ``,
        `\`\`\`bash`,
        `npm run build`,
        `\`\`\``,
        ``,
        `## Scale context`,
        ``,
        `[Describe project size and complexity]`,
        ``,
      ].join("\n");
    case "design":
      return [
        `# Design config`,
        ``,
        `## Scan targets`,
        ``,
        `- [List UI-related source files]`,
        `- [List style files]`,
        ``,
        `## Design context`,
        ``,
        `[Describe the design surface \u2014 web app, CLI, plugin, etc.]`,
        ``,
      ].join("\n");
    case "product":
      return [
        `# Product config`,
        ``,
        `## Scan targets`,
        ``,
        `- [List product-relevant files]`,
        ``,
        `## Stage context`,
        ``,
        `[Describe project stage \u2014 prototype, beta, production, etc.]`,
        ``,
      ].join("\n");
    case "visionary":
      return [
        `# Visionary config`,
        ``,
        `## Scan targets`,
        ``,
        `- [List strategic context files]`,
        ``,
        `## Cold-boot web scan topics`,
        ``,
        `- [What to search for on first boot]`,
        ``,
        `## Landscape domain`,
        ``,
        `[What space is this project in?]`,
        ``,
      ].join("\n");
    case "values":
      return [
        `# ${name} config`,
        ``,
        `## Scan targets`,
        ``,
        `- [List values-relevant context files]`,
        ``,
        `## Core values`,
        ``,
        `[Describe the values that matter for this project]`,
        ``,
      ].join("\n");
    default:
      return `# ${name} config\n`;
  }
}

// ── Helpers ────────────────────────────────────────────────────────

function ensureDir(dir: string): void {
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
}

function writeIfMissing(filePath: string, content: string): boolean {
  if (fs.existsSync(filePath)) return false;
  fs.writeFileSync(filePath, content, "utf-8");
  return true;
}

// ── Public API ─────────────────────────────────────────────────────

export interface ScaffoldResult {
  created: string[];
  skipped: string[];
}

/**
 * Full team scaffold. Creates .parts/ with PARTS.md, per-role directories
 * (config, state, sessions), and self-contained SKILL.md files.
 * Skips any file that already exists.
 */
export function scaffoldTeam(projectRoot: string): ScaffoldResult {
  const partsDir = join(projectRoot, ".parts");
  const skillsDir = join(partsDir, "skills");
  const created: string[] = [];
  const skipped: string[] = [];

  // PARTS.md
  ensureDir(partsDir);
  if (writeIfMissing(join(partsDir, "PARTS.md"), PARTS_TEMPLATE)) {
    created.push(".parts/PARTS.md");
  } else {
    skipped.push(".parts/PARTS.md");
  }

  // Per-role directories
  for (const role of ROLES) {
    const roleDir = join(partsDir, role);
    const stateDir = join(roleDir, ".state");
    const sessionsDir = join(roleDir, "sessions");

    ensureDir(roleDir);
    ensureDir(stateDir);
    ensureDir(sessionsDir);

    // config.md
    const configPath = `.parts/${role}/config.md`;
    if (writeIfMissing(join(roleDir, "config.md"), configStub(role))) {
      created.push(configPath);
    } else {
      skipped.push(configPath);
    }

    // .state/current.md (empty)
    const statePath = `.parts/${role}/.state/current.md`;
    if (writeIfMissing(join(stateDir, "current.md"), "")) {
      created.push(statePath);
    } else {
      skipped.push(statePath);
    }

    // sessions/.gitkeep
    const gitkeepPath = `.parts/${role}/sessions/.gitkeep`;
    if (writeIfMissing(join(sessionsDir, ".gitkeep"), "")) {
      created.push(gitkeepPath);
    }
  }

  // Skills
  for (const role of ROLES) {
    const skillDir = join(skillsDir, `project-${role}`);
    ensureDir(skillDir);

    const skillPath = `.parts/skills/project-${role}/SKILL.md`;
    if (writeIfMissing(join(skillDir, "SKILL.md"), SKILLS[role])) {
      created.push(skillPath);
    } else {
      skipped.push(skillPath);
    }
  }

  return { created, skipped };
}

/**
 * Overwrites SKILL.md files with latest defaults.
 * Never touches config.md, state files, or session logs.
 */
export function refreshTeamSkills(projectRoot: string): ScaffoldResult {
  const skillsDir = join(projectRoot, ".parts", "skills");
  const updated: string[] = [];

  for (const role of ROLES) {
    const skillDir = join(skillsDir, `project-${role}`);
    ensureDir(skillDir);
    const skillFile = join(skillDir, "SKILL.md");
    fs.writeFileSync(skillFile, SKILLS[role], "utf-8");
    updated.push(`.parts/skills/project-${role}/SKILL.md`);
  }

  return { created: updated, skipped: [] };
}
